    private String getAppAndSheet( String apname , User user ) throws JSONException{
        //取得所有頁籤
        Map<String, App> allAppInAccount = AppManager.getInstalledApplications(apname, user, Const.USER);

        //取得頁籤下所有表單並轉成json格式
        /*
          json的格式為: 陣列中的每一個物件代表一組頁籤以及其下的表單
          [
           {
             appName:"頁籤1",
             appPath:"xxxxx",
             sheets:["表單1","表單2"],
             sheetIndexs:["1","2"]
            },
            { .... }
          ]
         */
        JSONArray jsonResult = new JSONArray();
        for( App app : allAppInAccount.values() ){ //針對每一個頁籤(app)
            if( "/ragic-setup".equals(app.getPath()) ){ //排除Ragic系統管理頁籤
                continue;
            }
            JSONObject jsonApp = new JSONObject();
            jsonApp.put("appName",app.getApplicationName()); //頁籤名稱
            jsonApp.put("appPath",app.getPath());           //頁籤路徑

            JSONArray jsonSheets = new JSONArray();
            JSONArray jsonSheetIndexs = new JSONArray();
            for( App.Form form : app.getForms().values() ){ //取得一個頁籤下的所有表單
                jsonSheets.put(form.getName());             //表單名
                jsonSheetIndexs.put(form.getSheetIndex());  //表單sheetIndex
            }
            jsonApp.put("sheets",jsonSheets);
            jsonApp.put("sheetIndexs",jsonSheetIndexs);

            jsonResult.put(jsonApp);
        }

        return jsonResult.toString(2); //toString帶入數字後 回傳的json會自動換行縮排，且縮排的空格數量由此數字決定
    }

    //取得某表單的SelectionTitleField(STF)
    private String getSelectionTitleField( String apname , String path , String sheetIndex ) throws JSONException{
        NUIForm form = new APIQuery(apname,path,sheetIndex).getForm();
        CellInfo info = form.getSelectionFieldCellInfo();
        String fieldName = info.getValue();
        int domainId = info.getDomainId();
        JSONObject json = new JSONObject();
        json.put("fieldName",fieldName);
        json.put("domainId",domainId);
        return json.toString(2);
    }

    //取得某表单的资料数量
    private int getSheetDataCount( String apname , String path , String sheetIndex ){
        APIQuery q = new APIQuery(apname,path,sheetIndex);
        NUIForm form = q.getForm();
        return form.getNumberOfEntries();
    }

    //取得某帳號下的所有群組及使用者数量
    private String getGroups( String apname , RagicBundle bundle ) throws Exception{
        JSONArray result = new JSONArray();
        try {
            Account acc = Account.getInstance(apname);
            Set<String> groupSet = acc.getGroups();
            groupSet.add(Const.G_ADMIN);
            Set<String> activeUsers = acc.getActiveUsers();
            Set<String> internalUsers = acc.getInternalUsers();
            Set<String> externalUsers = acc.getExternalUsers();


            //取得所有群組的使用者資料
            for(String group:groupSet) { //對於每一個group ，建構出 { group : "群組名" , usersCount : 此群組使用者數量 }
                JSONObject groupJo = new JSONObject();
                groupJo.put("group", group);
                Set<String> userEmails = acc.getGroupUserEmails(group);
                long usersCount = userEmails.stream().filter( userEmail -> activeUsers.contains(userEmail) ).count();
                groupJo.put("usersCount", usersCount);
                result.put(groupJo);
            }

            JSONObject groupAllActive = new JSONObject();
            groupAllActive.put("group", bundle.getString("massCreate_AllActiveUsers"));
            groupAllActive.put("usersCount", activeUsers.size());
            result.put(groupAllActive);

            JSONObject groupAllInternal = new JSONObject();
            groupAllInternal.put("group", bundle.getString("massCreate_AllInternalUsers"));
            groupAllInternal.put("usersCount", internalUsers.size());
            result.put(groupAllInternal);

            JSONObject groupAllExternal = new JSONObject();
            groupAllExternal.put("group", bundle.getString("massCreate_AllExternalUsers"));
            groupAllExternal.put("usersCount", externalUsers.size());
            result.put(groupAllExternal);
        } finally{
            return result.toString(2);
        }
    }
    private String getUsersFromGroup( String apname , String group , String limitCount , RagicBundle bundle ) throws Exception{
        boolean outOflimitCount = false;
        int limit = Integer.parseInt(limitCount);
        JSONObject result = new JSONObject();
        JSONArray users = new JSONArray();
        try {
            Account acc = Account.getInstance(apname);
            Set<String> groupSet = acc.getGroups();
            groupSet.add(Const.G_ADMIN);
            Set<String> activeUsers = acc.getActiveUsers();
            int addingCount = 0 ; //用來記錄已經加入多少使用者了
            if( bundle.getString("massCreate_AllActiveUsers").equals(group) ){ //使用者選的群組是 所有使用者
                for( String userEmail : activeUsers ){
                    if( addingCount >= limit ){
                        outOflimitCount = true;
                        break;
                    }
                    users.put(acc.getUserName(userEmail));
                    addingCount++;
                }
            }else if( bundle.getString("massCreate_AllInternalUsers").equals(group) ){ //使用者選的群組是 所有內部使用者
                 for( String userEmail : acc.getInternalUsers() ){
                    if( addingCount >= limit ){
                        outOflimitCount = true;
                        break;
                    }
                    users.put(acc.getUserName(userEmail));
                    addingCount++;
                }
            }else if( bundle.getString("massCreate_AllExternalUsers").equals(group) ){ //使用者選的群組是 所有外部使用者
                for( String userEmail : acc.getExternalUsers() ){
                    if( addingCount >= limit ){
                        outOflimitCount = true;
                        break;
                    }
                    users.put(acc.getUserName(userEmail));
                    addingCount++;
                }
            }else{
                Set<String> userEmails = acc.getGroupUserEmails(group);
                for( String userEmail : userEmails ){
                    if(activeUsers.contains(userEmail)) {
                        if( addingCount >= limit ){
                            outOflimitCount = true;
                            break;
                        }
                        users.put(acc.getUserName(userEmail));
                        addingCount++;
                    }
                }
            }
        }finally{
            result.put("outOflimitCount",outOflimitCount);
            result.put("users",users);
            return result.toString(2);
        }
    }

    private String getDesignerFilter( String apname , String path , String sheetIndex ) throws Exception{

        NUIForm form = AppManager.getListingPage(apname, path, Integer.parseInt(sheetIndex) );
        Map<Integer, NUIFilterSet> test = form.getDesignerFilterSet();
        JSONArray designerFilterArray = new JSONArray();

        //取出共通篩選，並以這種形式回傳 [ {sequence:篩選1的序號 , filterName:篩選1的名稱} , {sequence:篩選2的序號 , filterName:篩選2的名稱} ... ]
        for ( Map.Entry<Integer, NUIFilterSet> e : form.getDesignerFilterSet().entrySet() ){
            JSONObject designerFilterObj = new JSONObject();
            int seq = e.getKey();
            NUIFilterSet filter = e.getValue();
            designerFilterObj.put("sequence",seq);
            designerFilterObj.put("filterName",filter.getName());
            designerFilterArray.put(designerFilterObj);
        }
        return designerFilterArray.toString(2);
    }

    private String getFieldsOfSheet( String apname , String path , String sheetIndex , boolean includeSubtable , JSONArray queryAttributes ) throws Exception{
        NUIForm form = AppManager.getFormPage(apname,path,Integer.parseInt(sheetIndex) );
        JSONArray fieldsOfSheetArray = new JSONArray();
        for( CellInfo info:form.getAllFields(includeSubtable) ){
            JSONObject fieldsOfSheetObj = new JSONObject();
            int domainId = info.getDomainId();
            String infoValue = info.getValue();
            String fieldDisplayText = Encoder.encjs(infoValue);
            fieldsOfSheetObj.put("domainId",domainId);
            fieldsOfSheetObj.put("fieldDisplayText",fieldDisplayText);

            //塞入額外要找的欄位屬性
            for( int i = 0 ; i < queryAttributes.length() ; i++ ){
                String attributeName = queryAttributes.getString(i);
                String attributeValue = info.getAttribute(attributeName);
                if( attributeValue != null ){
                    fieldsOfSheetObj.put( attributeName , attributeValue );
                }
            }

            fieldsOfSheetArray.put(fieldsOfSheetObj);
        }
        return fieldsOfSheetArray.toString(2);
    }

    private String getLinkSheetCount( String apname , String path , String sheetIndex , String filterSeq ){
        APIQuery aq = new APIQuery( apname , path , sheetIndex );

        //設定共通篩選
        if( filterSeq != null && !filterSeq.isEmpty() && !"-1".equals(filterSeq) ){ //有設定過濾的話
            NUIForm form = AppManager.getListingPage(apname, path, Integer.parseInt(sheetIndex) );
            NUIFilterSet filterSet =  form.getDesignerFilterSet().get( Integer.parseInt(filterSeq) );
            aq.setFilters( filterSet.getFilters() );
        }
        aq.setMaxRetrieveFieldSize(1024);

        //取得資料總數
        int count = 0;
        APIResultsFull af = aq.getAPIResultsFull();
        while( af.hasNext() ){
            APIEntry ae = af.next();
            count++;
        }

        return String.valueOf(count);
    }

    private String getLinkSheetData( String apname , String path , String sheetIndex , String fieldDomainId , String filterSeq , String limitCount ) throws Exception{
        if( fieldDomainId == null || fieldDomainId.isEmpty() || "-1".equals(fieldDomainId) ) return ""; //沒有指定欄位的話，不知道要傳回什麼

        APIQuery aq = new APIQuery( apname , path , sheetIndex );
        aq.setUpdateMode();
        //設定共通篩選
        if( filterSeq != null && !filterSeq.isEmpty() && !"-1".equals(filterSeq) ){ //有設定過濾的話
            NUIForm form = AppManager.getListingPage(apname, path, Integer.parseInt(sheetIndex) );
            NUIFilterSet filterSet =  form.getDesignerFilterSet().get( Integer.parseInt(filterSeq) );
            aq.setFilters( filterSet.getFilters() );
        }

        //取得資料
        boolean outOflimitCount = false;
        int limit = Integer.parseInt(limitCount);
        JSONObject result = new JSONObject();
        JSONArray datas = new JSONArray();
        int addingCount = 0 ; //用來記錄目前已經加入幾筆資料
        APIResultsFull af = aq.getAPIResultsFull();
        while( af.hasNext() ){
            if( addingCount >= limit ){
                outOflimitCount = true;
                break;
            }
            APIEntry ae = af.next();
            String fieldValue = ae.getFieldValue( Integer.parseInt(fieldDomainId) );
            datas.put(fieldValue);
            addingCount++;
        }
        result.put("outOflimitCount",outOflimitCount);
        result.put("datas",datas);
        return result.toString(2);
    }

    private String getSelectionFieldsOfSheet( String apname , String path , String sheetIndex ) throws Exception{
        NUIForm form = AppManager.getFormPage(apname,path,Integer.parseInt(sheetIndex) );
        APIQuery aq = new APIQuery( apname , path , sheetIndex );
        aq.setUpdateMode();
        JSONArray fieldsOfSheetArray = new JSONArray();
        for( CellInfo info:form.getAllFields(false) ){
            if( !info.isSelection() )continue; //如果這一個欄位不是選擇欄位就跳過
            if( info.getAttribute("usrref") != null )continue; //如果是選擇使用者的就跳過
            if( info.getAttribute("grpref") != null )continue; //如果是選擇群組的就跳過
            if( info.getAttribute("mvp") != null )continue; //如果這個選項的值是從其他表單得到的的就跳過
            JSONObject fieldsOfSheetObj = new JSONObject();
            int domainId = info.getDomainId();
            String infoValue = info.getValue();
            String fieldDisplayText = infoValue;
            int optionCount = Account.getInstance(apname).getLOV(domainId).size();
            fieldsOfSheetObj.put("domainId",domainId);
            fieldsOfSheetObj.put("fieldDisplayText",fieldDisplayText);
            fieldsOfSheetObj.put("optionCount",optionCount);
            fieldsOfSheetArray.put(fieldsOfSheetObj);
        }
        return fieldsOfSheetArray.toString(2);
    }

    private String getOptionsFromFieldDomainId( String apname , String path , String sheetIndex , String fieldDomainId , String limitCount ) throws Exception{
        //取得資料
        boolean outOflimitCount = false;
        int limit = Integer.parseInt(limitCount);
        int domainId = Integer.parseInt(fieldDomainId);
        JSONObject result = new JSONObject();
        JSONArray options = new JSONArray();
        int addingCount = 0 ; //用來記錄目前已經加入幾筆資料
        List<String> optionList = Account.getInstance(apname).getLOV(domainId);
        for( String option : optionList ){
            if( addingCount >= limit ){
                outOflimitCount = true;
                break;
            }
            options.put(option);
            addingCount++;
        }
        result.put("outOflimitCount",outOflimitCount);
        result.put("options",options);
        return result.toString(2);
    }

    private String getFieldsDomainIdOfAttribute( String apname , String path , String sheetIndex , boolean includeSubtable , String Attr , String attValue ){
        NUIForm form = AppManager.getFormPage(apname,path,Integer.parseInt(sheetIndex) );
        APIQuery aq = new APIQuery( apname , path , sheetIndex );
        aq.setUpdateMode();
        JSONArray domainIdArray = new JSONArray();
        for( CellInfo info:form.getAllFields(includeSubtable) ){
            String attributeValue = info.getAttribute(Attr);
            if( attributeValue == null || !attributeValue.equals(attValue)  )continue;
            domainIdArray.put(info.getDomainId());
        }
        return domainIdArray.toString();
    }

